	@TestFactory
	Stream<DynamicTest> generatedTraceCombinationsShouldStaySupportedAndMapped() {
		return CombinationCase.stream()
				.map(testCase -> DynamicTest.dynamicTest(testCase.displayName(), () -> assertSupported(testCase)));
	}

	private static void assertSupported(CombinationCase testCase) {
		QueryTraceAnalyzer.Analysis analysis = QueryTraceAnalyzer.analyze(testCase.createQuery());

		assertThat(analysis.isSupported())
				.as(testCase.displayName())
				.isTrue();
		assertThat(analysis.isDistinct()).isEqualTo(testCase.withWrappers);
		assertThat(analysis.getCollectedPatterns()).hasSize(testCase.statementPatternCount());
		assertThat(analysis.getFilters()).hasSize(testCase.filterLineCount());

		List<QueryTraceAnalyzer.CollectedLine> lines = analysis.getCollectedLines();
		assertThat(lines).hasSize(testCase.totalLineCount());
		assertThat(lines).filteredOn(line -> "pattern".equals(line.getKind()))
				.hasSize(testCase.statementPatternCount());
		assertThat(lines).filteredOn(line -> "filter".equals(line.getKind())).hasSize(testCase.filterLineCount());
		assertThat(lines).filteredOn(line -> "optionalStart".equals(line.getKind()))
				.hasSize(testCase.hasOptional() ? 1 : 0);
		assertThat(lines).filteredOn(line -> "optionalEnd".equals(line.getKind()))
				.hasSize(testCase.hasOptional() ? 1 : 0);
		assertThat(lines).filteredOn(line -> "values".equals(line.getKind())).hasSize(testCase.hasValues() ? 1 : 0);
		assertThat(lines).filteredOn(line -> "bind".equals(line.getKind())).hasSize(testCase.hasBind() ? 1 : 0);
		assertThat(lines).filteredOn(line -> "minus".equals(line.getKind())).hasSize(testCase.hasMinus() ? 1 : 0);
		assertThat(lines).filteredOn(line -> "minusEnd".equals(line.getKind())).hasSize(testCase.hasMinus() ? 1 : 0);

		int nextStepIndex = 0;
		for (int i = 0; i < lines.size(); i++) {
			QueryTraceAnalyzer.CollectedLine line = lines.get(i);
			assertThat(line.getDisplayIndex()).as(testCase.displayName()).isEqualTo(i);
			assertThat(line.getIndentDepth()).isPositive();
			if (line.getStepIndex() >= 0) {
				assertThat(line.getStepIndex()).as(testCase.displayName()).isEqualTo(nextStepIndex++);
			} else {
				assertThat(line.getStepIndex()).isEqualTo(-1);
			}
		}
		assertThat(nextStepIndex).isEqualTo(testCase.stepLineCount());

		if (testCase.hasValues()) {
			assertThat(indexOfKind(lines, "values")).isZero();
		}
		if (testCase.hasBind()) {
			int bindIndex = indexOfKind(lines, "bind");
			if (testCase.hasOptional()) {
				assertThat(bindIndex).isGreaterThan(indexOfKind(lines, "optionalEnd"));
			}
			if (testCase.hasMinus()) {
				assertThat(bindIndex).isLessThan(indexOfKind(lines, "minus"));
			}
		}
		if (testCase.hasOptional()) {
			int optionalStart = indexOfKind(lines, "optionalStart");
			int optionalEnd = indexOfKind(lines, "optionalEnd");
			int optionalPattern = firstPatternIndexAfter(lines, optionalStart);
			assertThat(optionalStart).isLessThan(optionalPattern);
			assertThat(optionalPattern).isLessThan(optionalEnd);
			assertThat(lines.get(optionalPattern).getIndentDepth())
					.isEqualTo(lines.get(optionalStart).getIndentDepth() + 1);
		}
		if (testCase.hasMinus()) {
			int minusStart = indexOfKind(lines, "minus");
			int minusEnd = indexOfKind(lines, "minusEnd");
			assertThat(minusStart).isLessThan(minusEnd);
			for (int i = minusStart + 1; i < minusEnd; i++) {
				if ("pattern".equals(lines.get(i).getKind())) {
					assertThat(lines.get(i).getIndentDepth()).isEqualTo(lines.get(minusStart).getIndentDepth() + 1);
				}
			}
		}
		if (testCase.filterMode > 0) {
			assertThat(lines.get(lines.size() - 1).getKind()).isEqualTo("filter");
		}
		if (testCase.optionalMode == 2) {
			assertThat(indexOfKind(lines, "filter")).isLessThan(indexOfKind(lines, "optionalStart"));
		}
		if (testCase.optionalMode == 3) {
			int optionalStart = indexOfKind(lines, "optionalStart");
			int optionalEnd = indexOfKind(lines, "optionalEnd");
			int conditionalFilter = firstFilterIndexAfter(lines, optionalStart);
			assertThat(conditionalFilter).isGreaterThan(optionalStart);
			assertThat(conditionalFilter).isLessThan(optionalEnd);
		}

		QueryTraceRecorder recorder = new QueryTraceRecorder(analysis);
		List<QueryTraceAnalyzer.CollectedLine> stepLines = new ArrayList<>();
		for (QueryTraceAnalyzer.CollectedLine line : lines) {
			if (line.getStepIndex() >= 0) {
				stepLines.add(line);
			}
		}
		for (QueryTraceAnalyzer.CollectedLine stepLine : stepLines) {
			recorder.recordProbe(stepLine.getTraceTarget(), EmptyBindingSet.getInstance());
			recorder.recordMatch(stepLine.getTraceTarget(), EmptyBindingSet.getInstance(),
					EmptyBindingSet.getInstance());
		}

		QueryTrace trace = recorder.toTrace();
		assertThat(trace.getLines()).hasSize(lines.size());
		assertThat(trace.getPatterns()).hasSize(testCase.statementPatternCount());
		assertThat(trace.getFrames()).hasSize(stepLines.size() * 2);
		assertThat(trace.getFilters()).hasSize(testCase.filterLineCount());

		int patternIndex = 0;
		for (int i = 0; i < stepLines.size(); i++) {
			QueryTraceAnalyzer.CollectedLine stepLine = stepLines.get(i);
			QueryTrace.Frame probe = trace.getFrames().get(i * 2);
			QueryTrace.Frame match = trace.getFrames().get(i * 2 + 1);
			assertFrameForLine(probe, stepLine, "probe");
			assertFrameForLine(match, stepLine, "match");
			if ("pattern".equals(stepLine.getKind())) {
				assertThat(probe.getPatternId()).isEqualTo("sp-" + patternIndex);
				assertThat(probe.getPatternIndex()).isEqualTo(patternIndex);
				assertThat(match.getPatternId()).isEqualTo("sp-" + patternIndex);
				assertThat(match.getPatternIndex()).isEqualTo(patternIndex);
				patternIndex++;
			} else {
				assertThat(probe.getPatternId()).isNull();
				assertThat(probe.getPatternIndex()).isEqualTo(-1);
				assertThat(match.getPatternId()).isNull();
				assertThat(match.getPatternIndex()).isEqualTo(-1);
			}
		}
	}

	private static void assertFrameForLine(QueryTrace.Frame frame, QueryTraceAnalyzer.CollectedLine line,
			String event) {
		assertThat(frame.getEvent()).isEqualTo(event);
		assertThat(frame.getLineId()).isEqualTo("line-" + line.getDisplayIndex());
		assertThat(frame.getStepIndex()).isEqualTo(line.getStepIndex());
	}

	private static int indexOfKind(List<QueryTraceAnalyzer.CollectedLine> lines, String kind) {
		for (int i = 0; i < lines.size(); i++) {
			if (kind.equals(lines.get(i).getKind())) {
				return i;
			}
		}
		return -1;
	}

	private static int firstPatternIndexAfter(List<QueryTraceAnalyzer.CollectedLine> lines, int displayIndex) {
		for (int i = displayIndex + 1; i < lines.size(); i++) {
			if ("pattern".equals(lines.get(i).getKind())) {
				return i;
			}
		}
		return -1;
	}

	private static int firstFilterIndexAfter(List<QueryTraceAnalyzer.CollectedLine> lines, int displayIndex) {
		for (int i = displayIndex + 1; i < lines.size(); i++) {
			if ("filter".equals(lines.get(i).getKind())) {
				return i;
			}
		}
		return -1;
	}

	private static final class CombinationCase {
		private final int valuesMode;
		private final int bindMode;
		private final int minusMode;
		private final int optionalMode;
		private final int filterMode;
		private final int baseJoinMode;
		private final int projectionMode;
		private final boolean withWrappers;
		private final boolean reverseJoinOrder;

		private CombinationCase(int ordinal) {
			int remainder = ordinal;
			valuesMode = remainder & 0b11;
			remainder >>= 2;
			bindMode = remainder & 0b11;
			remainder >>= 2;
			minusMode = remainder & 0b11;
			remainder >>= 2;
			optionalMode = remainder & 0b11;
			remainder >>= 2;
			filterMode = remainder & 0b11;
			remainder >>= 2;
			baseJoinMode = remainder & 0b11;
			remainder >>= 2;
			projectionMode = remainder & 0b1;
			remainder >>= 1;
			withWrappers = (remainder & 0b1) != 0;
			remainder >>= 1;
			reverseJoinOrder = (remainder & 0b1) != 0;
		}

		private static int count() {
			return TOTAL_CASES;
		}

		private static Stream<CombinationCase> stream() {
			return IntStream.range(0, TOTAL_CASES).mapToObj(CombinationCase::new);
		}

		private String displayName() {
			return "v" + valuesMode + "-b" + bindMode + "-m" + minusMode + "-o" + optionalMode + "-f" + filterMode
					+ "-j" + baseJoinMode + "-p" + projectionMode + "-w" + (withWrappers ? 1 : 0) + "-r"
					+ (reverseJoinOrder ? 1 : 0);
		}

		private QueryRoot createQuery() {
			TupleExpr current = createBaseExpr();
			if (hasValues()) {
				current = join(createValuesExpr(), current);
			}
			if (hasOptional()) {
				current = createOptionalExpr(current);
			}
			if (hasBind()) {
				Extension extension = new Extension(current);
				extension.addElement(new ExtensionElem(createBindValueExpr(), "bound"));
				current = extension;
			}
			if (hasMinus()) {
				current = new Difference(current, createMinusExpr());
			}
			if (filterMode > 0) {
				current = new Filter(current, createTopLevelFilter());
			}
			current = new Projection(current, createProjectionElems());
			if (withWrappers) {
				current = new Slice(new Distinct(current), 0, 5);
			}
			return new QueryRoot(current);
		}

		private TupleExpr createBaseExpr() {
			List<TupleExpr> args = new ArrayList<>();
			switch (baseJoinMode) {
			case 0:
				args.add(statementPattern("a", KIND, "kind"));
				break;
			case 1:
				args.add(statementPattern("a", KIND, "kind"));
				args.add(statementPattern("a", KNOWS, "friend"));
				break;
			case 2:
				args.add(statementPattern("a", KIND, "kind"));
				args.add(statementPattern("a", KNOWS, "friend"));
				args.add(statementPattern("friend", NAME, "friendName"));
				break;
			default:
				args.add(statementPattern("a", KIND, "kind", "graph"));
				args.add(statementPattern("a", KNOWS, "friend"));
				break;
			}
			return joinChain(args);
		}

		private TupleExpr createValuesExpr() {
			BindingSetAssignment assignment = new BindingSetAssignment();
			if (valuesMode == 1) {
				assignment.setBindingSets(List.of(bindingSet("a", ALICE)));
			} else if (valuesMode == 2) {
				assignment.setBindingSets(List.of(bindingSet("a", ALICE), bindingSet("a", BOB)));
			} else {
				assignment.setBindingSets(List.of(bindingSet("a", ALICE, "kind", PERSON)));
			}
			return assignment;
		}

		private TupleExpr createOptionalExpr(TupleExpr leftArg) {
			StatementPattern optionalPattern = statementPattern("a", LABEL, "optionalLabel");
			if (optionalMode == 1) {
				LeftJoin leftJoin = new LeftJoin(leftArg, optionalPattern);
				leftJoin.setAlgorithm(LeftJoinIterator.class.getSimpleName());
				return leftJoin;
			}
			Compare condition = new Compare(new Var("a"), new ValueConstant(ALICE), CompareOp.NE);
			if (optionalMode == 2) {
				LeftJoin leftJoin = new LeftJoin(new Filter(leftArg, condition), optionalPattern);
				leftJoin.setAlgorithm(LeftJoinIterator.class.getSimpleName());
				return leftJoin;
			}
			LeftJoin leftJoin = new LeftJoin(leftArg, optionalPattern, condition);
			leftJoin.setAlgorithm(LeftJoinIterator.class.getSimpleName());
			return leftJoin;
		}

		private TupleExpr createMinusExpr() {
			if (minusMode == 1) {
				return statementPattern("a", NAME, "minusName");
			}
			if (minusMode == 2) {
				return joinChain(List.of(
						statementPattern("a", KNOWS, "minusFriend"),
						statementPattern("minusFriend", NAME, "minusFriendName")));
			}
			return statementPattern("a", KIND, "minusKind", "minusGraph");
		}

		private org.eclipse.rdf4j.query.algebra.ValueExpr createBindValueExpr() {
			if (bindMode == 1) {
				return new Var("a");
			}
			if (bindMode == 2) {
				return new ValueConstant(FIXED);
			}
			return new Bound(new Var("a"));
		}

		private org.eclipse.rdf4j.query.algebra.ValueExpr createTopLevelFilter() {
			if (filterMode == 1) {
				return new Compare(new Var("a"), new ValueConstant(BOB), CompareOp.NE);
			}
			if (filterMode == 2) {
				return new Bound(new Var("a"));
			}
			return new SameTerm(new Var("a"), new Var("a"));
		}

		private ProjectionElemList createProjectionElems() {
			ProjectionElemList projectionElemList = new ProjectionElemList();
			projectionElemList.addElement(new ProjectionElem("a"));
			if (projectionMode == 1) {
				projectionElemList.addElement(new ProjectionElem("kind"));
			}
			return projectionElemList;
		}

		private TupleExpr joinChain(List<TupleExpr> args) {
			List<TupleExpr> orderedArgs = reverseJoinOrder ? reversed(args) : args;
			TupleExpr current = orderedArgs.get(0);
			for (int i = 1; i < orderedArgs.size(); i++) {
				current = join(current, orderedArgs.get(i));
			}
			return current;
		}

		private boolean hasValues() {
			return valuesMode > 0;
		}

		private boolean hasBind() {
			return bindMode > 0;
		}

		private boolean hasMinus() {
			return minusMode > 0;
		}

		private boolean hasOptional() {
			return optionalMode > 0;
		}

		private int statementPatternCount() {
			return baseStatementPatternCount() + (hasOptional() ? 1 : 0) + minusStatementPatternCount();
		}

		private int baseStatementPatternCount() {
			if (baseJoinMode == 0) {
				return 1;
			}
			if (baseJoinMode == 1 || baseJoinMode == 3) {
				return 2;
			}
			return 3;
		}

		private int minusStatementPatternCount() {
			if (!hasMinus()) {
				return 0;
			}
			return minusMode == 2 ? 2 : 1;
		}

		private int stepLineCount() {
			return statementPatternCount() + (hasValues() ? 1 : 0) + (hasBind() ? 1 : 0) + (hasMinus() ? 1 : 0);
		}

		private int filterLineCount() {
			return (filterMode > 0 ? 1 : 0) + ((optionalMode == 2 || optionalMode == 3) ? 1 : 0);
		}

		private int totalLineCount() {
			return stepLineCount() + filterLineCount() + (hasOptional() ? 2 : 0) + (hasMinus() ? 1 : 0);
		}
	}

	private static StatementPattern statementPattern(String subjectName, IRI predicate, String objectName) {
		return statementPattern(subjectName, predicate, objectName, null);
	}

	private static StatementPattern statementPattern(String subjectName, IRI predicate, String objectName,
			String contextName) {
		return new StatementPattern(new Var(subjectName),
				new Var("p_" + subjectName + "_" + objectName, predicate),
				new Var(objectName),
				contextName == null ? null : new Var(contextName, GRAPH));
	}

	private static Join join(TupleExpr leftArg, TupleExpr rightArg) {
		Join join = new Join(leftArg, rightArg);
		join.setAlgorithm(JoinIterator.class.getSimpleName());
		return join;
	}

	private static List<TupleExpr> reversed(List<TupleExpr> args) {
		List<TupleExpr> reversed = new ArrayList<>(args);
		java.util.Collections.reverse(reversed);
		return reversed;
	}

	private static MapBindingSet bindingSet(String firstName, Value firstValue) {
		MapBindingSet bindingSet = new MapBindingSet();
		bindingSet.addBinding(firstName, firstValue);
		return bindingSet;
	}

	private static MapBindingSet bindingSet(String firstName, Value firstValue, String secondName, Value secondValue) {
		MapBindingSet bindingSet = new MapBindingSet();
		bindingSet.addBinding(firstName, firstValue);
		bindingSet.addBinding(secondName, secondValue);
		return bindingSet;
	}
